package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.JsonParseException;
import com.google.gson.TypeAdapter;
import com.google.gson.annotations.JsonAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.annotation.Annotation;
import java.lang.reflect.Field;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;
import java.lang.reflect.Type;

class ReflectiveTypeAdapterFactoryTest {

  private ReflectiveTypeAdapterFactory reflectiveTypeAdapterFactory;
  private ConstructorConstructor constructorConstructor;
  private FieldNamingStrategy fieldNamingStrategy;
  private Excluder excluder;
  private JsonAdapterAnnotationTypeAdapterFactory jsonAdapterFactory;

  @BeforeEach
  void setUp() {
    constructorConstructor = mock(ConstructorConstructor.class);
    fieldNamingStrategy = mock(FieldNamingStrategy.class);
    excluder = mock(Excluder.class);
    jsonAdapterFactory = mock(JsonAdapterAnnotationTypeAdapterFactory.class);
    reflectiveTypeAdapterFactory = new ReflectiveTypeAdapterFactory(
        constructorConstructor,
        fieldNamingStrategy,
        excluder,
        jsonAdapterFactory,
        Collections.emptyList());
  }

  private BoundField invokeCreateBoundField(
      Gson context,
      Field field,
      Method accessor,
      String name,
      TypeToken<?> fieldType,
      boolean serialize,
      boolean deserialize,
      boolean blockInaccessible) throws Exception {

    Method method = ReflectiveTypeAdapterFactory.class.getDeclaredMethod(
        "createBoundField",
        Gson.class, Field.class, Method.class, String.class, TypeToken.class,
        boolean.class, boolean.class, boolean.class);
    method.setAccessible(true);
    return (BoundField) method.invoke(
        reflectiveTypeAdapterFactory,
        context, field, accessor, name, fieldType, serialize, deserialize, blockInaccessible);
  }

  @Test
  void createBoundField_withJsonAdapterAnnotation_usesJsonAdapterFactory() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("fieldWithJsonAdapter");
    Method accessor = SampleClass.class.getDeclaredMethod("getFieldWithJsonAdapter");
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<?> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), eq(gson), eq(fieldType), any(JsonAdapter.class)))
        .thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "fieldWithJsonAdapter", fieldType, true, true, true);

    assertNotNull(boundField);
    // Test write method calls accessor.invoke and typeAdapter.write
    JsonWriter writer = mock(JsonWriter.class);
    SampleClass source = new SampleClass();
    doNothing().when(typeAdapterMock).write(any(), any());

    boundField.write(writer, source);
    verify(typeAdapterMock).write(eq(writer), any());

    // Test readIntoField reads and sets field
    JsonReader reader = mock(JsonReader.class);
    when(((TypeAdapter<Object>) typeAdapterMock).read(reader)).thenReturn("value");

    boundField.readIntoField(reader, source);
    assertEquals("value", source.fieldWithJsonAdapter);
  }

  @Test
  void createBoundField_withoutJsonAdapterAnnotation_getsAdapterFromContext() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("fieldWithoutJsonAdapter");
    Method accessor = null;
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<?> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), any(), any(), any())).thenReturn(null);
    when(gson.getAdapter(fieldType)).thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "fieldWithoutJsonAdapter", fieldType, true, true, false);

    assertNotNull(boundField);

    JsonWriter writer = mock(JsonWriter.class);
    SampleClass source = new SampleClass();
    source.fieldWithoutJsonAdapter = "testValue";
    doNothing().when(typeAdapterMock).write(any(), any());

    boundField.write(writer, source);
    verify(typeAdapterMock).write(eq(writer), eq("testValue"));

    JsonReader reader = mock(JsonReader.class);
    when(((TypeAdapter<Object>) typeAdapterMock).read(reader)).thenReturn("newValue");

    boundField.readIntoField(reader, source);
    assertEquals("newValue", source.fieldWithoutJsonAdapter);
  }

  @Test
  void createBoundField_write_skipsWhenSerializeFalse() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("fieldWithoutJsonAdapter");
    Method accessor = null;
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<?> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), any(), any(), any())).thenReturn(null);
    when(gson.getAdapter(fieldType)).thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "fieldWithoutJsonAdapter", fieldType, false, true, false);

    assertNotNull(boundField);

    JsonWriter writer = mock(JsonWriter.class);
    SampleClass source = new SampleClass();
    source.fieldWithoutJsonAdapter = "testValue";

    boundField.write(writer, source);
    verify(typeAdapterMock, never()).write(any(), any());
  }

  @Test
  void createBoundField_readIntoArray_throwsOnNullPrimitive() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("primitiveIntField");
    Method accessor = null;
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<Integer> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), any(), any(), any())).thenReturn(null);
    when(gson.getAdapter(fieldType)).thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "primitiveIntField", fieldType, true, true, false);

    assertNotNull(boundField);

    JsonReader reader = mock(JsonReader.class);
    when(typeAdapterMock.read(reader)).thenReturn(null);

    Object[] target = new Object[1];
    JsonParseException e = assertThrows(JsonParseException.class, () -> boundField.readIntoArray(reader, 0, target));
    assertTrue(e.getMessage().contains("null is not allowed as value for record component"));
  }

  @Test
  void createBoundField_readIntoField_throwsOnStaticFinalField() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("STATIC_FINAL_FIELD");
    Method accessor = null;
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<?> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), any(), any(), any())).thenReturn(null);
    when(gson.getAdapter(fieldType)).thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "STATIC_FINAL_FIELD", fieldType, true, true, false);

    assertNotNull(boundField);

    JsonReader reader = mock(JsonReader.class);
    when(((TypeAdapter<Object>) typeAdapterMock).read(reader)).thenReturn("value");

    JsonIOException e = assertThrows(JsonIOException.class, () -> boundField.readIntoField(reader, new SampleClass()));
    assertTrue(e.getMessage().contains("Cannot set value of 'static final'"));
  }

  @Test
  void createBoundField_write_throwsJsonIOExceptionOnAccessorInvocationException() throws Exception {
    Gson gson = mock(Gson.class);
    Field field = SampleClass.class.getDeclaredField("fieldWithJsonAdapter");
    Method accessor = SampleClass.class.getDeclaredMethod("getFieldWithJsonAdapter");
    TypeToken<?> fieldType = TypeToken.get(field.getGenericType());

    TypeAdapter<?> typeAdapterMock = mock(TypeAdapter.class);
    when(jsonAdapterFactory.getTypeAdapter(any(), eq(gson), eq(fieldType), any(JsonAdapter.class)))
        .thenReturn(typeAdapterMock);

    BoundField boundField = invokeCreateBoundField(
        gson, field, accessor, "fieldWithJsonAdapter", fieldType, true, true, true);

    assertNotNull(boundField);

    JsonWriter writer = mock(JsonWriter.class);
    SampleClass source = new SampleClass();

    // Mock accessor.invoke to throw InvocationTargetException
    Method spyAccessor = spy(accessor);
    doThrow(new InvocationTargetException(new RuntimeException("cause"))).when(spyAccessor).invoke(source);

    // Use reflection to create BoundField with spyAccessor
    BoundField boundFieldWithSpyAccessor = invokeCreateBoundField(
        gson, field, spyAccessor, "fieldWithJsonAdapter", fieldType, true, true, true);

    JsonIOException e = assertThrows(JsonIOException.class, () -> boundFieldWithSpyAccessor.write(writer, source));
    assertTrue(e.getMessage().contains("Accessor"));
    assertTrue(e.getCause().getMessage().equals("cause"));
  }

  // Sample class for testing purposes
  static class SampleClass {
    @JsonAdapter(MockJsonAdapter.class)
    String fieldWithJsonAdapter = "initialValue";

    String fieldWithoutJsonAdapter;

    int primitiveIntField;

    static final String STATIC_FINAL_FIELD = "constant";

    public String getFieldWithJsonAdapter() {
      return fieldWithJsonAdapter;
    }
  }

  // Mock JsonAdapter annotation for fieldWithJsonAdapter
  public @interface MockJsonAdapter extends JsonAdapter {
    @Override
    Class<? extends TypeAdapter<?>> value() default MockTypeAdapter.class;
  }

  // Mock TypeAdapter class
  public static class MockTypeAdapter extends TypeAdapter<Object> {
    @Override
    public void write(JsonWriter out, Object value) throws IOException {
    }

    @Override
    public Object read(JsonReader in) throws IOException {
      return null;
    }
  }
}
